import json

# Check what we got from the query
all_articles_result = locals()['var_functions.query_db:24']

print(f"Type: {type(all_articles_result)}")
if isinstance(all_articles_result, str):
    print(f"Is string, ends with .json: {all_articles_result.endswith('.json')}")
    if len(all_articles_result) <= 200:
        print(f"Value (truncated): {all_articles_result}")
    else:
        print(f"Is file path: {all_articles_result}")
elif isinstance(all_articles_result, list):
    print(f"Is list with {len(all_articles_result)} items")
    if len(all_articles_result) > 0:
        print(f"First item: {all_articles_result[0]}")
else:
    print(f"Unexpected type")

print('__RESULT__:')
print(json.dumps({'type': str(type(all_articles_result)), 'is_list': isinstance(all_articles_result, list)}))

